/// <summary>
/// This is an UIBuilder class for NewInjectionofCylinders report
/// </summary>
internal final class ETGNewInjectionofCylindersUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGNewInjectionofCylindersContract contract;
    DialogField                        dialogFromDate;
    DialogField                        dialogToDate;
    DialogField                        custAccount;

}

Method.Source:
public void build()
{
    contract            = this.dataContractObject() as ETGNewInjectionofCylindersContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGNewInjectionofCylindersContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGNewInjectionofCylindersContract, parmToDate), contract);
    custAccount         = this.addDialogField(methodStr(ETGNewInjectionofCylindersContract, parmCustAccount), contract);
}

public void postBuild()
{
    Dialog dialogobj    = this.dialog();

    super();
    dialogFromDate      = this.bindInfo().getDialogField(contract, methodStr(ETGNewInjectionofCylindersContract, parmFromDate));
    dialogToDate        = this.bindInfo().getDialogField(contract, methodStr(ETGNewInjectionofCylindersContract, parmToDate));
    custAccount         = this.bindInfo().getDialogField(contract, methodStr(ETGNewInjectionofCylindersContract, parmCustAccount));
    custAccount.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGNewInjectionofCylindersUIBuilder, custAccountMultiSelectLookup),this);
}

public void postRun()
{
    ETGNewInjectionofCylindersContract etgNewInjectionofCylindersContract = this.dataContractObject();
}

/// <summary>
/// This is lookup method for Cust account parameter
/// </summary>
/// <param name = "_formStringControl">FormStringControl</param>
public void custAccountMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conCustTable;

    qbds = query.addDataSource(tableNum(CustTable));

    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(CustTable,AccountNum));

    qbds = qbds.addDataSource(tableNum(DirPartyTable));
    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(DirPartyTable,Name));
    qbds.relations(true);
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conCustTable);
}
